     1→import React from 'react';
     2→import ExportedImage from 'next-image-export-optimizer';
     3→import { siteConfig } from '../../site.config';
     4→import { getCdnImageUrl } from '@/lib/image-utils';
     5→
     6→// Each palette defines a gradient background and text color for light/dark modes
     7→const palettes = [
     8→  // Warm amber
     9→  'bg-gradient-to-br from-amber-50 via-orange-50 to-yellow-100 dark:from-amber-950 dark:via-orange-950 dark:to-yellow-950 text-amber-800 dark:text-amber-200',
    10→  // Cool slate-blue
    11→  'bg-gradient-to-br from-slate-100 via-blue-50 to-indigo-100 dark:from-slate-900 dark:via-blue-950 dark:to-indigo-950 text-slate-700 dark:text-slate-200',
    12→  // Sage green
    13→  'bg-gradient-to-br from-emerald-50 via-green-50 to-teal-100 dark:from-emerald-950 dark:via-green-950 dark:to-teal-950 text-emerald-800 dark:text-emerald-200',
    14→  // Dusty rose
    15→  'bg-gradient-to-br from-rose-50 via-pink-50 to-fuchsia-100 dark:from-rose-950 dark:via-pink-950 dark:to-fuchsia-950 text-rose-800 dark:text-rose-200',
    16→  // Neutral stone
    17→  'bg-gradient-to-br from-stone-100 via-stone-50 to-zinc-100 dark:from-stone-900 dark:via-stone-950 dark:to-zinc-900 text-stone-700 dark:text-stone-300',
    18→  // Soft violet
    19→  'bg-gradient-to-br from-violet-50 via-purple-50 to-indigo-100 dark:from-violet-950 dark:via-purple-950 dark:to-indigo-950 text-violet-800 dark:text-violet-200',
    20→  // Warm teal
    21→  'bg-gradient-to-br from-teal-50 via-cyan-50 to-sky-100 dark:from-teal-950 dark:via-cyan-950 dark:to-sky-950 text-teal-800 dark:text-teal-200',
    22→];
    23→
    24→// Decorative accent line color per palette
    25→const accentColors = [
    26→  'bg-amber-400/60 dark:bg-amber-500/40',
    27→  'bg-indigo-400/60 dark:bg-indigo-400/40',
    28→  'bg-emerald-400/60 dark:bg-emerald-500/40',
    29→  'bg-rose-400/60 dark:bg-rose-400/40',
    30→  'bg-stone-400/60 dark:bg-stone-500/40',
    31→  'bg-violet-400/60 dark:bg-violet-400/40',
    32→  'bg-teal-400/60 dark:bg-teal-400/40',
    33→];
    34→
    35→// Shorten a long title to a concise label for the cover
    36→function shortenTitle(text: string): string {
    37→  // Already short enough — use as-is
    38→  if (text.length <= 12) return text;
    39→
    40→  // CJK characters: take first 4 chars
    41→  const cjk = /[\u4e00-\u9fff\u3400-\u4dbf\u3000-\u303f]/;
    42→  if (cjk.test(text)) {
    43→    return text.slice(0, 4);
    44→  }
    45→
    46→  // Latin text: take up to first 2 words
    47→  const words = text.split(/\s+/);
    48→  if (words.length >= 2 && words.slice(0, 2).join(' ').length <= 20) {
    49→    return words.slice(0, 2).join(' ');
    50→  }
    51→  return words[0];
    52→}
    53→
    54→interface CoverImageProps {
    55→  title: string;
    56→  slug: string;
    57→  src?: string;
    58→  className?: string;
    59→}
    60→
    61→export default function CoverImage({ title, slug, src, className = "h-full w-full object-cover" }: CoverImageProps) {
    62→  // Use text-based cover when no src or explicit "text:" prefix
    63→  const isTextCover = !src || src.startsWith('text:');
    64→  const coverText = !src
    65→    ? shortenTitle(title)
    66→    : src.startsWith('text:')
    67→      ? (src.replace('text:', '').trim() || shortenTitle(title))
    68→      : '';
    69→    
    70→  const paletteIndex = slug.length % palettes.length;
    71→  const paletteClass = palettes[paletteIndex];
    72→  const accentClass = accentColors[paletteIndex];
    73→
    74→  if (isTextCover) {
    75→    return (
    76→      <div className={`h-full w-full ${paletteClass} flex items-center justify-center p-6 text-center relative overflow-hidden`}>
    77→        <div className={`absolute top-0 left-1/2 -translate-x-1/2 w-12 h-0.5 rounded-full ${accentClass} mt-4`} />
    78→        <span className="font-serif font-bold tracking-tight break-words text-xl md:text-2xl leading-tight max-w-[80%]">
    79→          {coverText}
    80→        </span>
    81→        <div className={`absolute bottom-0 left-1/2 -translate-x-1/2 w-12 h-0.5 rounded-full ${accentClass} mb-4`} />
    82→      </div>
    83→    );
    84→  }
    85→
    86→  const cdnBaseUrl = siteConfig.images?.cdnBaseUrl ?? '';
    87→  const imageSrc = getCdnImageUrl(src!, cdnBaseUrl);
    88→  const isCdn = cdnBaseUrl && imageSrc !== src;
    89→  const isDev = process.env.NODE_ENV === 'development';
    90→
    91→  return (
    92→    <ExportedImage
    93→      src={imageSrc}
    94→      alt={title}
    95→      className={className}
    96→      fill
    97→      sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
    98→      unoptimized={isDev || !!isCdn}
    99→    />
   100→  );
   101→}
