     1→/**
     2→ * Prepend a CDN base URL to a local image path.
     3→ * External URLs (http/https) and special values (text:, data:) are returned as-is.
     4→ */
     5→export function getCdnImageUrl(src: string, cdnBaseUrl: string): string {
     6→  if (!cdnBaseUrl || !src) return src;
     7→  if (src.startsWith('http') || src.startsWith('//')) return src;
     8→  if (src.startsWith('text:') || src.startsWith('data:')) return src;
     9→  const base = cdnBaseUrl.replace(/\/$/, '');
    10→  const path = src.startsWith('/') ? src : `/${src}`;
    11→  return `${base}${path}`;
    12→}
