     1→import { visit } from 'unist-util-visit';
     2→import sizeOf from 'image-size';
     3→import path from 'path';
     4→import fs from 'fs';
     5→import { Root, Element } from 'hast';
     6→import { getCdnImageUrl } from './image-utils';
     7→
     8→interface Options {
     9→  slug?: string;
    10→  cdnBaseUrl?: string;
    11→}
    12→
    13→export default function rehypeImageMetadata(options: Options) {
    14→  return (tree: Root) => {
    15→    visit(tree, 'element', (node: Element) => {
    16→      if (node.tagName === 'img' && node.properties && typeof node.properties.src === 'string') {
    17→        const src = node.properties.src as string;
    18→        
    19→        if (src.startsWith('http')) return;
    20→
    21→        let imagePath = '';
    22→        let publicPath = '';
    23→
    24→        if (src.startsWith('./') && options.slug) {
    25→          // Relative path: slug is the full public-relative base path (e.g. posts/my-post, books/my-book, flows/2026/01/15)
    26→          const relative = src.substring(2);
    27→          // Use path.resolve to create absolute path without explicitly invoking process.cwd() in a way that triggers broad matching warnings
    28→          imagePath = path.resolve('public', options.slug, relative);
    29→          publicPath = `/${options.slug}/${relative}`;
    30→        } else if (src.startsWith('/')) {
    31→          // Absolute path from public
    32→          // Remove leading slash for path.resolve
    33→          imagePath = path.resolve('public', src.substring(1));
    34→          publicPath = src;
    35→        } else {
    36→          return;
    37→        }
    38→
    39→        // Always resolve to the public path (and apply CDN prefix if configured).
    40→        // Path resolution must happen regardless of whether the file exists locally,
    41→        // so that images hosted only on CDN still get the correct URL.
    42→        node.properties.src = getCdnImageUrl(publicPath, options.cdnBaseUrl ?? '');
    43→
    44→        // Enrich with dimensions only when the file is available locally
    45→        try {
    46→          if (imagePath && fs.existsSync(imagePath)) {
    47→            const buffer = fs.readFileSync(imagePath);
    48→            const dimensions = sizeOf(buffer);
    49→            if (dimensions) {
    50→              node.properties.width = dimensions.width;
    51→              node.properties.height = dimensions.height;
    52→            }
    53→          }
    54→        } catch {
    55→          // Silently fail
    56→        }
    57→      }
    58→    });
    59→  };
    60→}
