     1→import fs from 'fs';
     2→import path from 'path';
     3→
     4→const args = process.argv.slice(2);
     5→
     6→// Parse arguments
     7→const folderPath = args.find(arg => !arg.startsWith('--'));
     8→const titleArgIndex = args.indexOf('--title');
     9→const title = titleArgIndex > -1 ? args[titleArgIndex + 1] : '';
    10→const sortArg = args.indexOf('--sort');
    11→const sortOrder = sortArg > -1 ? args[sortArg + 1] : 'name'; // name, date, or none
    12→const copyImages = !args.includes('--no-copy');
    13→
    14→// Supported image extensions
    15→const IMAGE_EXTENSIONS = ['.jpg', '.jpeg', '.png', '.gif', '.webp', '.svg', '.avif'];
    16→
    17→function isImageFile(filename: string): boolean {
    18→  const ext = path.extname(filename).toLowerCase();
    19→  return IMAGE_EXTENSIONS.includes(ext);
    20→}
    21→
    22→function getImageFiles(dir: string, sort: string): string[] {
    23→  const files = fs.readdirSync(dir)
    24→    .filter(f => {
    25→      const filePath = path.join(dir, f);
    26→      return fs.statSync(filePath).isFile() && isImageFile(f);
    27→    });
    28→
    29→  switch (sort) {
    30→    case 'name':
    31→      return files.sort((a, b) => a.localeCompare(b, undefined, { numeric: true }));
    32→    case 'date':
    33→      return files.sort((a, b) => {
    34→        const statA = fs.statSync(path.join(dir, a));
    35→        const statB = fs.statSync(path.join(dir, b));
    36→        return statA.mtimeMs - statB.mtimeMs;
    37→      });
    38→    case 'none':
    39→    default:
    40→      return files;
    41→  }
    42→}
    43→
    44→if (!folderPath) {
    45→  console.error('Please provide an image folder path.');
    46→  console.error('Usage: bun run new-from-images <folder> [--title "Post Title"] [--sort name|date|none] [--no-copy]');
    47→  console.error('');
    48→  console.error('Options:');
    49→  console.error('  --title     Custom title for the post (default: folder name)');
    50→  console.error('  --sort      Sort images by: name (default), date, or none');
    51→  console.error('  --no-copy   Reference images in place instead of copying');
    52→  process.exit(1);
    53→}
    54→
    55→if (!fs.existsSync(folderPath) || !fs.statSync(folderPath).isDirectory()) {
    56→  console.error(`Error: "${folderPath}" is not a valid directory.`);
    57→  process.exit(1);
    58→}
    59→
    60→// Get image files
    61→const imageFiles = getImageFiles(folderPath, sortOrder);
    62→
    63→if (imageFiles.length === 0) {
    64→  console.error(`Error: No image files found in "${folderPath}".`);
    65→  console.error(`Supported formats: ${IMAGE_EXTENSIONS.join(', ')}`);
    66→  process.exit(1);
    67→}
    68→
    69→console.log(`Found ${imageFiles.length} image(s) in folder.`);
    70→
    71→// Generate slug from title or folder name
    72→const folderName = path.basename(folderPath);
    73→const postTitle = title || folderName.replace(/[-_]/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
    74→const slug = (title || folderName)
    75→  .toLowerCase()
    76→  .replace(/[^a-z0-9]+/g, '-')
    77→  .replace(/(^-|-$)+/g, '');
    78→
    79→const date = new Date().toISOString().split('T')[0];
    80→const dirName = `${date}-${slug}`;
    81→const dirPath = path.join(process.cwd(), 'content', 'posts', dirName);
    82→const imagesDir = path.join(dirPath, 'images');
    83→
    84→// Check if post already exists
    85→if (fs.existsSync(dirPath)) {
    86→  console.error(`Error: Post already exists at ${dirPath}`);
    87→  process.exit(1);
    88→}
    89→
    90→// Create directories
    91→fs.mkdirSync(imagesDir, { recursive: true });
    92→console.log(`Created directory: ${dirPath}`);
    93→
    94→// Copy or reference images
    95→const images: { filename: string; relativePath: string }[] = [];
    96→
    97→for (const file of imageFiles) {
    98→  const srcPath = path.join(folderPath, file);
    99→
   100→  if (copyImages) {
   101→    const destPath = path.join(imagesDir, file);
   102→    fs.copyFileSync(srcPath, destPath);
   103→    images.push({ filename: file, relativePath: `./images/${file}` });
   104→    console.log(`  Copied: ${file}`);
   105→  } else {
   106→    // Use absolute path from project root
   107→    const absoluteSrcPath = path.resolve(srcPath);
   108→    const relativePath = path.relative(dirPath, absoluteSrcPath);
   109→    images.push({ filename: file, relativePath });
   110→    console.log(`  Referenced: ${file}`);
   111→  }
   112→}
   113→
   114→// Generate markdown content
   115→const imageMarkdown = images
   116→  .map((img, index) => `![Image ${index + 1}](${img.relativePath})`)
   117→  .join('\n\n');
   118→
   119→const content = `---
   120→title: "${postTitle}"
   121→date: "${date}"
   122→excerpt: "A collection of ${images.length} images."
   123→category: "Gallery"
   124→tags: ["images", "gallery"]
   125→authors: ["Amytis"]
   126→layout: "post"
   127→draft: false
   128→latex: false
   129→---
   130→
   131→${imageMarkdown}
   132→`;
   133→
   134→// Write markdown file
   135→const targetPath = path.join(dirPath, 'index.mdx');
   136→fs.writeFileSync(targetPath, content);
   137→
   138→console.log(`\nCreated new post from images:`);
   139→console.log(`  Post: ${targetPath}`);
   140→console.log(`  Images: ${images.length} file(s)${copyImages ? ' (copied)' : ' (referenced)'}`);
   141→console.log(`\nYou can edit the post at: ${dirPath}`);
