     1→import fs from 'fs';
     2→import path from 'path';
     3→import { siteConfig } from '../site.config';
     4→
     5→const srcDir = path.join(process.cwd(), 'content', 'posts');
     6→const seriesSrcDir = path.join(process.cwd(), 'content', 'series');
     7→const booksSrcDir = path.join(process.cwd(), 'content', 'books');
     8→const flowsSrcDir = path.join(process.cwd(), 'content', 'flows');
     9→const destDir = path.join(process.cwd(), 'public', 'posts');
    10→const booksDestDir = path.join(process.cwd(), 'public', 'books');
    11→const flowsDestDir = path.join(process.cwd(), 'public', 'flows');
    12→
    13→function copyRecursive(src: string, dest: string) {
    14→  if (!fs.existsSync(src)) return;
    15→  
    16→  if (!fs.existsSync(dest)) {
    17→    fs.mkdirSync(dest, { recursive: true });
    18→  }
    19→
    20→  const entries = fs.readdirSync(src, { withFileTypes: true });
    21→
    22→  for (const entry of entries) {
    23→    const srcPath = path.join(src, entry.name);
    24→    const destPath = path.join(dest, entry.name);
    25→
    26→    if (entry.isDirectory()) {
    27→      copyRecursive(srcPath, destPath);
    28→    } else {
    29→      // Copy all files except markdown source
    30→      if (!entry.name.endsWith('.md') && !entry.name.endsWith('.mdx')) {
    31→        let shouldCopy = true;
    32→        if (fs.existsSync(destPath)) {
    33→          const srcStat = fs.statSync(srcPath);
    34→          const destStat = fs.statSync(destPath);
    35→          if (srcStat.mtimeMs <= destStat.mtimeMs) {
    36→            shouldCopy = false;
    37→          }
    38→        }
    39→
    40→        if (shouldCopy) {
    41→          fs.copyFileSync(srcPath, destPath);
    42→          // console.log(`Copied: ${entry.name} -> ${destPath}`);
    43→        }
    44→      }
    45→    }
    46→  }
    47→}
    48→
    49→function getSlugFromFilename(filename: string): string {
    50→  const nameWithoutExt = filename.replace(/\.mdx?$/, '');
    51→  const dateRegex = /^(\d{4}-\d{2}-\d{2})-(.*)$/;
    52→  const match = nameWithoutExt.match(dateRegex);
    53→
    54→  if (match && !siteConfig.posts?.includeDateInUrl) {
    55→    return match[2];
    56→  }
    57→  return nameWithoutExt;
    58→}
    59→
    60→function processPosts() {
    61→  if (fs.existsSync(srcDir)) {
    62→    const entries = fs.readdirSync(srcDir, { withFileTypes: true });
    63→
    64→    entries.forEach((entry) => {
    65→      if (entry.isDirectory()) {
    66→        const targetName = getSlugFromFilename(entry.name);
    67→        const srcPostDir = path.join(srcDir, entry.name);
    68→        const destPostDir = path.join(destDir, targetName);
    69→
    70→        console.log(`Processing Post: ${entry.name} -> ${targetName}`);
    71→        copyRecursive(srcPostDir, destPostDir);
    72→      }
    73→    });
    74→  }
    75→}
    76→
    77→// Check if a directory is a post folder (contains index.md or index.mdx)
    78→function isPostFolder(dirPath: string): boolean {
    79→  return fs.existsSync(path.join(dirPath, 'index.md')) ||
    80→         fs.existsSync(path.join(dirPath, 'index.mdx'));
    81→}
    82→
    83→// Check if a directory is an asset folder (not a post folder)
    84→function isAssetFolder(dirPath: string): boolean {
    85→  return !isPostFolder(dirPath);
    86→}
    87→
    88→function processSeries() {
    89→  if (!fs.existsSync(seriesSrcDir)) return;
    90→
    91→  const seriesEntries = fs.readdirSync(seriesSrcDir, { withFileTypes: true });
    92→
    93→  seriesEntries.forEach((seriesEntry) => {
    94→    if (seriesEntry.isDirectory()) {
    95→      const seriesPath = path.join(seriesSrcDir, seriesEntry.name);
    96→      const items = fs.readdirSync(seriesPath, { withFileTypes: true });
    97→
    98→      // First pass: identify shared asset folders at series level (folders that are NOT posts)
    99→      const sharedAssetFolders = items
   100→        .filter(item => item.isDirectory() && isAssetFolder(path.join(seriesPath, item.name)))
   101→        .map(item => item.name);
   102→
   103→      // Process items in series folder
   104→      items.forEach(item => {
   105→        if (item.isFile() && (item.name.endsWith('.md') || item.name.endsWith('.mdx'))) {
   106→          // File-based post or series index
   107→          const targetSlug = item.name.startsWith('index.') ? seriesEntry.name : getSlugFromFilename(item.name);
   108→          const destPostDir = path.join(destDir, targetSlug);
   109→
   110→          console.log(`Processing Series File: ${item.name} -> ${targetSlug}`);
   111→
   112→          // Only copy shared asset folders (like images/, assets/), not sibling post folders
   113→          sharedAssetFolders.forEach(folderName => {
   114→            const srcPath = path.join(seriesPath, folderName);
   115→            const destPath = path.join(destPostDir, folderName);
   116→            copyRecursive(srcPath, destPath);
   117→          });
   118→
   119→          // Copy any non-markdown files at the series root level
   120→          items.filter(sub => sub.isFile() && !sub.name.endsWith('.md') && !sub.name.endsWith('.mdx'))
   121→            .forEach(sub => {
   122→              const srcPath = path.join(seriesPath, sub.name);
   123→              const destPath = path.join(destPostDir, sub.name);
   124→              if (!fs.existsSync(destPostDir)) {
   125→                fs.mkdirSync(destPostDir, { recursive: true });
   126→              }
   127→              fs.copyFileSync(srcPath, destPath);
   128→            });
   129→
   130→        } else if (item.isDirectory() && isPostFolder(path.join(seriesPath, item.name))) {
   131→          // Folder-based post: copy only its own assets
   132→          const targetSlug = getSlugFromFilename(item.name);
   133→          const itemSrcPath = path.join(seriesPath, item.name);
   134→          const destPostDir = path.join(destDir, targetSlug);
   135→
   136→          console.log(`Processing Series Post Folder: ${item.name} -> ${targetSlug}`);
   137→
   138→          // Copy everything from the post folder EXCEPT markdown files
   139→          const subItems = fs.readdirSync(itemSrcPath, { withFileTypes: true });
   140→          subItems.forEach(sub => {
   141→            const srcPath = path.join(itemSrcPath, sub.name);
   142→            const destPath = path.join(destPostDir, sub.name);
   143→
   144→            if (sub.isDirectory()) {
   145→              copyRecursive(srcPath, destPath);
   146→            } else if (!sub.name.endsWith('.md') && !sub.name.endsWith('.mdx')) {
   147→              if (!fs.existsSync(destPostDir)) {
   148→                fs.mkdirSync(destPostDir, { recursive: true });
   149→              }
   150→              fs.copyFileSync(srcPath, destPath);
   151→            }
   152→          });
   153→        }
   154→      });
   155→    }
   156→  });
   157→}
   158→
   159→function processBooks() {
   160→  if (!fs.existsSync(booksSrcDir)) return;
   161→
   162→  const entries = fs.readdirSync(booksSrcDir, { withFileTypes: true });
   163→
   164→  entries.forEach((entry) => {
   165→    if (entry.isDirectory()) {
   166→      const srcBookDir = path.join(booksSrcDir, entry.name);
   167→      const destBookDir = path.join(booksDestDir, entry.name);
   168→
   169→      console.log(`Processing Book: ${entry.name}`);
   170→      copyRecursive(srcBookDir, destBookDir);
   171→    }
   172→  });
   173→}
   174→
   175→function processFlows() {
   176→  if (!fs.existsSync(flowsSrcDir)) return;
   177→
   178→  // Walk content/flows/YYYY/MM/ structure for folder-based flows with co-located assets
   179→  const yearDirs = fs.readdirSync(flowsSrcDir, { withFileTypes: true });
   180→  for (const yearEntry of yearDirs) {
   181→    if (!yearEntry.isDirectory() || !/^\d{4}$/.test(yearEntry.name)) continue;
   182→    const yearPath = path.join(flowsSrcDir, yearEntry.name);
   183→
   184→    const monthDirs = fs.readdirSync(yearPath, { withFileTypes: true });
   185→    for (const monthEntry of monthDirs) {
   186→      if (!monthEntry.isDirectory() || !/^\d{2}$/.test(monthEntry.name)) continue;
   187→      const monthPath = path.join(yearPath, monthEntry.name);
   188→
   189→      const dayItems = fs.readdirSync(monthPath, { withFileTypes: true });
   190→      for (const dayItem of dayItems) {
   191→        // Only process folder-based flows (DD/ directories with index.mdx)
   192→        if (!dayItem.isDirectory()) continue;
   193→        const rawName = dayItem.name;
   194→        if (!/^\d{2}$/.test(rawName)) continue;
   195→
   196→        const srcFlowDir = path.join(monthPath, rawName);
   197→        const destFlowDir = path.join(flowsDestDir, yearEntry.name, monthEntry.name, rawName);
   198→
   199→        console.log(`Processing Flow: ${yearEntry.name}/${monthEntry.name}/${rawName}`);
   200→        copyRecursive(srcFlowDir, destFlowDir);
   201→      }
   202→    }
   203→  }
   204→}
   205→
   206→console.log('Copying assets...');
   207→processPosts();
   208→processSeries();
   209→processBooks();
   210→processFlows();
   211→console.log('Assets copied successfully.');

