     5→/** Build a minimal HAST tree containing a single <img> node. */
     6→function makeTree(src: string): Root {
     7→  return {
     8→    type: 'root',
     9→    children: [
    10→      {
    11→        type: 'element',
    12→        tagName: 'img',
    13→        properties: { src },
    14→        children: [],
    15→      } satisfies Element,
    16→    ],
    17→  };
    18→}
    19→
    20→function imgSrc(tree: Root): unknown {
    21→  return (tree.children[0] as Element).properties.src;
    22→}
